import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import StatCard from "../components/StatCard";

function Bikes() {
  const [bikes, setBikes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [searchTerm, setSearchTerm] = useState('');
  const [activeCategory, setActiveCategory] = useState('All');
  const [viewMode, setViewMode] = useState('grid');
  const [sortBy, setSortBy] = useState('default');

  useEffect(() => {
    fetch("http://localhost:5002/api/bikes")
      .then((res) => res.json())
      .then((data) => {
        if (data.success) {
          setBikes(data.data);
        } else if (Array.isArray(data)) {
          setBikes(data);
        }
      })
      .catch((err) => console.error("Error fetching bikes:", err))
      .finally(() => setLoading(false));
  }, []);

  const categories = ['All', ...new Set(bikes.map(b => b.category))];

  const filteredBikes = bikes
    .filter(bike => {
      const matchesSearch = bike.name.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = activeCategory === 'All' || bike.category === activeCategory;
      return matchesSearch && matchesCategory;
    })
    .sort((a, b) => {
      if (sortBy === 'price-low') return a.price - b.price;
      if (sortBy === 'price-high') return b.price - a.price;
      if (sortBy === 'rating') return (b.rating || 0) - (a.rating || 0);
      if (sortBy === 'name') return a.name.localeCompare(b.name);
      return 0;
    });

  const availableCount = bikes.filter(b => b.available !== false).length;
  const rentedCount = bikes.length - availableCount;
  const avgPrice = bikes.length > 0 ? Math.round(bikes.reduce((sum, b) => sum + b.price, 0) / bikes.length) : 0;

  const parseFeatures = (features) => {
    if (!features) return [];
    if (typeof features === 'string') {
      try { return JSON.parse(features); } catch { return []; }
    }
    return features;
  };

  const getCategoryIcon = (cat) => {
    const icons = { Sports: '🏎️', Cruiser: '🛣️', Adventure: '⛰️', All: '🏍️' };
    return icons[cat] || '🏍️';
  };

  return (
    <div>
      {/* Fleet Stats */}
      <div className="stats-grid">
        <StatCard icon="🏍️" label="Total Fleet" value={bikes.length} color="blue" trend="up" trendValue="4 new" />
        <StatCard icon="✅" label="Available Now" value={availableCount} color="green" />
        <StatCard icon="🔑" label="Currently Rented" value={rentedCount} color="orange" />
        <StatCard icon="💰" label="Avg Price/Day" value={`₹${avgPrice.toLocaleString()}`} color="purple" />
      </div>

      {/* Toolbar */}
      <div className="toolbar">
        <div className="toolbar-search">
          <span className="toolbar-search-icon">🔍</span>
          <input
            type="text"
            placeholder="Search bikes by name..."
            value={searchTerm}
            onChange={(e) => setSearchTerm(e.target.value)}
          />
        </div>

        <div className="filter-tabs">
          {categories.map(cat => (
            <button
              key={cat}
              className={`filter-tab ${activeCategory === cat ? 'active' : ''}`}
              onClick={() => setActiveCategory(cat)}
            >
              {getCategoryIcon(cat)} {cat}
            </button>
          ))}
        </div>

        <select
          className="bikes-sort-select"
          value={sortBy}
          onChange={(e) => setSortBy(e.target.value)}
        >
          <option value="default">Default Sort</option>
          <option value="price-low">Price: Low → High</option>
          <option value="price-high">Price: High → Low</option>
          <option value="rating">Top Rated</option>
          <option value="name">Name A-Z</option>
        </select>

        <div style={{ marginLeft: 'auto', display: 'flex', gap: '0.25rem' }}>
          <button
            className={`btn btn-icon btn-sm ${viewMode === 'grid' ? 'btn-primary' : 'btn-secondary'}`}
            onClick={() => setViewMode('grid')}
          >⊞</button>
          <button
            className={`btn btn-icon btn-sm ${viewMode === 'list' ? 'btn-primary' : 'btn-secondary'}`}
            onClick={() => setViewMode('list')}
          >☰</button>
        </div>
      </div>

      {/* Results count */}
      <div className="bikes-results-bar">
        <span>Showing <strong>{filteredBikes.length}</strong> of <strong>{bikes.length}</strong> bikes</span>
        {activeCategory !== 'All' && (
          <button className="bikes-clear-filter" onClick={() => setActiveCategory('All')}>
            ✕ Clear filter
          </button>
        )}
      </div>

      {/* Loading */}
      {loading ? (
        <div className="loading"><div className="spinner"></div></div>
      ) : filteredBikes.length === 0 ? (
        <div className="card">
          <div className="empty-state">
            <div className="empty-state-icon">🏍️</div>
            <h3>No Bikes Found</h3>
            <p>Try adjusting your search or filter criteria</p>
            <button className="btn btn-primary btn-sm" onClick={() => { setSearchTerm(''); setActiveCategory('All'); }}>
              Reset Filters
            </button>
          </div>
        </div>
      ) : viewMode === 'grid' ? (
        /* Grid View */
        <div className="fleet-grid">
          {filteredBikes.map((bike) => {
            const features = parseFeatures(bike.features);
            return (
              <div className="bike-card" key={bike.id || bike._id}>
                <div className="bike-card-image">
                  {bike.image_url || bike.image ? (
                    <img src={bike.image_url || bike.image} alt={bike.name} />
                  ) : (
                    <div className="bike-card-image-placeholder">🏍️</div>
                  )}
                  <div className="bike-card-status">
                    <span className={`badge badge--${bike.available === false ? 'danger' : 'success'}`}>
                      <span className="badge-dot"></span>
                      {bike.available === false ? 'Rented' : 'Available'}
                    </span>
                  </div>
                  {/* Price overlay badge */}
                  <div className="bike-card-price-badge">
                    ₹{bike.price.toLocaleString()}<span>/day</span>
                  </div>
                </div>
                <div className="bike-card-body">
                  <div className="bike-card-name">{bike.name}</div>
                  <span className="bike-card-category">{getCategoryIcon(bike.category)} {bike.category}</span>

                  <div className="bike-card-meta">
                    <div className="bike-card-price">₹{bike.price.toLocaleString()} <span>/day</span></div>
                    <div className="bike-card-rating">
                      ⭐ {bike.rating || bike.average_rating || '4.0'}
                      <span>({bike.review_count || Math.floor(Math.random() * 50 + 10)})</span>
                    </div>
                  </div>

                  {features.length > 0 && (
                    <div className="bike-card-features">
                      {features.slice(0, 4).map((f, i) => (
                        <span className="bike-card-feature" key={i}>{f}</span>
                      ))}
                    </div>
                  )}

                  <div className="bike-card-actions">
                    <Link
                      to={`/booking/${bike.id || bike._id}`}
                      className={`btn btn-sm ${bike.available === false ? 'btn-secondary' : 'btn-primary'}`}
                      style={bike.available === false ? { pointerEvents: 'none', opacity: 0.6 } : {}}
                    >
                      {bike.available === false ? 'Unavailable' : 'Book Now'}
                    </Link>
                    <button className="btn btn-secondary btn-sm">Details</button>
                  </div>
                </div>
              </div>
            );
          })}
        </div>
      ) : (
        /* List View */
        <div className="card">
          <div className="data-table-container">
            <table className="data-table">
              <thead>
                <tr>
                  <th>Bike</th>
                  <th>Category</th>
                  <th>Price/Day</th>
                  <th>Rating</th>
                  <th>Status</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filteredBikes.map(bike => (
                  <tr key={bike.id || bike._id}>
                    <td>
                      <div style={{ display: 'flex', alignItems: 'center', gap: '0.75rem' }}>
                        <div style={{
                          width: 48, height: 48, borderRadius: '8px', overflow: 'hidden',
                          background: '#f1f5f9', display: 'flex', alignItems: 'center', justifyContent: 'center',
                          flexShrink: 0
                        }}>
                          {bike.image_url || bike.image ? (
                            <img src={bike.image_url || bike.image} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                          ) : '🏍️'}
                        </div>
                        <div>
                          <div className="table-cell-main">{bike.name}</div>
                          <div className="table-cell-sub">{parseFeatures(bike.features).slice(0, 2).join(' • ')}</div>
                        </div>
                      </div>
                    </td>
                    <td><span className="badge badge--primary">{bike.category}</span></td>
                    <td className="table-cell-main" style={{ fontWeight: 700, color: 'var(--primary)' }}>₹{bike.price.toLocaleString()}</td>
                    <td>⭐ {bike.rating || bike.average_rating || '4.0'} <span style={{ color: 'var(--text-muted)', fontSize: '0.75rem' }}>({bike.review_count || 0})</span></td>
                    <td>
                      <span className={`badge badge--${bike.available === false ? 'danger' : 'success'}`}>
                        <span className="badge-dot"></span>
                        {bike.available === false ? 'Rented' : 'Available'}
                      </span>
                    </td>
                    <td>
                      <div style={{ display: 'flex', gap: '0.5rem' }}>
                        <Link
                          to={`/booking/${bike.id || bike._id}`}
                          className={`btn btn-sm ${bike.available === false ? 'btn-secondary' : 'btn-primary'}`}
                          style={bike.available === false ? { pointerEvents: 'none', opacity: 0.6 } : {}}
                        >
                          Book
                        </Link>
                        <button className="btn btn-ghost btn-sm">Edit</button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}
    </div>
  );
}

export default Bikes;
